-- Enrichment marathon batch: Pinry, Pipe, Pipedream, Pipedrive, Pipefy, Pipeline CRM, Pirsch, Pitivi

-- ── Pinry ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pinry is a free, open-source, self-hosted tiling image board that lets individuals and small teams save, tag, and search images, videos, and webpages in a Pinterest-style visual layout.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (volunteer-run open-source project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source project)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese (Simplified)$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Pinry Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pinry is a free, self-hosted, open-source image board for saving and tagging images and webpages. See features, setup, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pinry is a free and open-source, self-hosted tiling image board application that lets people save, tag, and organize images, videos, and webpages in a Pinterest-like visual grid, without relying on a third-party hosted service. The project began in 2013 and is maintained by a distributed community of open-source contributors on GitHub under the pinry organization, rather than by a single company; it is released under the permissive BSD-2-Clause license and has no headquarters, funding round, or commercial pricing tier attached to it. Technically, Pinry is built with a Python and Django REST Framework backend and a Vue.js frontend, and it ships official Docker images for ARMv7, ARMv8, and AMD64 architectures, which makes it straightforward to deploy on a home server, NAS, Raspberry Pi, or VPS via docker-compose. Core capabilities include tag-based search and organization, public and private boards, multi-user accounts, browser bookmarklets and extensions for one-click pinning, a command-line client, a full REST API, and interface translations into English, Simplified Chinese, and French. Pinry differentiates itself from hosted, ad-supported bookmarking and moodboard tools by giving users complete ownership of their data: nothing is stored on third-party servers, there is no tracking or advertising, and the entire codebase can be audited or modified. The pricing model is Open Source and free in the truest sense; the only cost is the infrastructure a user chooses to run it on, whether a spare home computer or a small cloud instance. Because it requires self-hosting and basic familiarity with Docker or Python and Django deployment, Pinry's practical audience is developers, sysadmins, and privacy-conscious hobbyists building a personal or small-team image and reference library, rather than mainstream consumers who want a zero-setup product. It is commonly compared to other self-hosted, privacy-respecting bookmarking and archiving tools such as Wallabag, Shaarli, and Linkding, as well as to hosted proprietary services like Pinterest and Pocket that Pinry was explicitly designed as a self-hosted alternative to. As of its most recent GitHub release (v2.1.13), the repository has around 3,400 stars and roughly 375 forks, reflecting a modest but steady niche audience within the self-hosted and home-lab software community.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eed72c85-b8c1-41ad-bfa6-c1d425f02b1e';

