-- ── Pipe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pipe is a fintech platform offering embedded capital and revenue-based financing tools that let SaaS, vertical software, and marketplace platforms extend fast, non-dilutive funding to their business customers.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Miami, Florida, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pipe Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pipe (pipe.com) offers embedded capital and revenue-based financing for SaaS and platforms. Explore features, pricing model, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pipe is a fintech company, founded in 2019 by Harry Hurst, Josh Mangel, and Zain Allarakhia and headquartered in Miami, Florida, that provides embedded financial infrastructure for software platforms and recurring-revenue businesses. Pipe launched publicly as a two-sided marketplace nicknamed the 'Nasdaq for revenue,' where SaaS companies could trade future subscription revenue to institutional investors for upfront, non-dilutive cash instead of taking on venture debt or giving up equity; the company raised over $300 million in funding, reached unicorn status in 2021 at roughly a $2 billion valuation, and at its peak had thousands of companies trading recurring revenue on the platform. Since then, Pipe has evolved its business model from a direct revenue-trading marketplace into an embedded finance operating system: its current flagship product, Pipe Capital, lets vertical SaaS providers, payment facilitators, and marketplace platforms offer their own small-business customers pre-approved, revenue-based financing and flexible repayment structures directly inside the software those customers already use, rather than sending them to a bank or third-party lender. This embedded, white-label approach is Pipe's key differentiator: instead of competing for end-customer financing relationships directly, Pipe partners with platforms (reported partners include UberEats, GoCardless, Housecall Pro, and Live Payments) so those platforms can add a get-paid-faster or lending feature and earn revenue share, while Pipe underwrites risk using the platform's own transaction data. Pricing is not publicly listed; Pipe operates on a custom, partner-negotiated commercial model, historically including a marketplace-style fee of around 1% charged to each side of a trade, now largely replaced by embedded-lending economics shared with platform partners, so prospective customers must contact Pipe's sales team. Pipe's target users are two distinct groups: software platforms and marketplaces that want to embed financial products for their merchants without building lending infrastructure themselves, and the small and mid-sized businesses that ultimately draw capital through those embedded offers. In the embedded finance and revenue-based financing space, Pipe competes with companies such as Capchase, Clearco, Uncapped, and Ramp, as well as with embedded-lending infrastructure providers like Stripe Capital. Pipe experienced notable leadership turnover in 2022, when several members of its founding team departed amid public disagreements, but the company has continued operating and expanding into new verticals, including a 2022 acquisition of Purely Capital to extend into media and entertainment financing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '61d2abfe-020b-44ad-8493-bab43284c852';

