-- ── Pipedream ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pipedream is a developer-focused integration and workflow automation platform that connects thousands of APIs, combining visual, no-code workflow building with the ability to drop in custom Node.js, Python, Go, or Bash code.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (acquired by Workday in November 2025)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pipedream Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pipedream connects thousands of APIs with code-level workflow automation. Compare Pipedream's features, credit-based pricing, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pipedream is a serverless integration and workflow automation platform built for developers, founded in San Francisco in 2019 by CEO Tod Sacerdoti and a founding team, with roots tracing back to the earlier open-source project RequestBin that was folded into Pipedream's product. The platform connects thousands of APIs and lets users build workflows that trigger on events, such as webhooks, schedules, app events, or email, and then run a mix of prebuilt no-code steps and custom code written directly in the browser using Node.js, Python, Go, or Bash, with access to npm and PyPI packages. This hybrid, code-optional architecture is Pipedream's core differentiator versus purely no-code automation tools: it targets developers and technical teams who want the speed of a visual builder without giving up the flexibility of writing real code when prebuilt actions fall short, and it also offers Pipedream Connect, an embedded-integration product that lets SaaS companies build in-app, white-labeled integration marketplaces for their own end users. Pipedream uses a hybrid, credit-metered pricing model: a Free plan includes a limited daily credit allowance, three active workflows, and one million AI tokens per month; paid, annually-billed plans are Basic at $29 per month, Advanced at $49 per month, and Connect at $99 per month, each priced higher on month-to-month billing, and each bundling a monthly credit allocation, with one credit corresponding to roughly 30 seconds of compute at 256MB of memory; a custom-priced Business tier adds single sign-on, HIPAA support, VPC deployment, and SLAs for larger organizations. In November 2025, Pipedream was acquired by Workday to extend AI agent integrations across Workday's enterprise HR and finance applications; Workday has stated that Pipedream's self-serve product and pricing remain live and unchanged following the acquisition. Pipedream's target users span individual developers automating personal or startup workflows, engineering teams building internal tooling, and software companies embedding third-party integrations into their own products via Connect. In the broader workflow-automation and integration-platform-as-a-service market, Pipedream is most often compared to Zapier and Make, both more no-code-oriented, n8n, a code-friendly and self-hostable competitor, and Workato, an enterprise-focused integration platform, with Pipedream generally positioned as the most developer-centric option among them due to its willingness to expose raw code execution alongside its visual builder.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9e7e7d01-4172-4d85-90b4-cb0af1a7c91d';

