-- ── Pipefy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pipefy is a no-code business process management and workflow automation platform that lets teams design, run, and automate structured processes like onboarding, procurement, and IT service requests using Kanban-style boards.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$500-1,000 employees (approximately 540 as of 2026)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (originally founded in Curitiba, Brazil)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Portuguese$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Pipefy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pipefy is a no-code BPM and workflow automation tool from Brazil. Compare Pipefy's plans, features, and alternatives like Monday and Kissflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pipefy is a no-code business process management (BPM) and workflow automation platform founded in 2015 in Curitiba, Brazil, by Alessio Alionco, who built the product after struggling to find an affordable, flexible way to manage recurring processes at his previous company. Pipefy has since grown into a global software company headquartered in San Francisco with a major engineering and operations presence still in Brazil, backed by investors including Insight Partners, Valor Capital, Qualcomm Ventures, and Founders Fund, and reports roughly 500 to 1,000 employees as of 2026. The platform lets business users, not just developers, design and run structured processes such as employee onboarding, procurement and purchase requests, IT service desks, accounts payable, and customer onboarding using customizable Kanban-style boards, conditional logic, SLAs, and no-code automation rules, and it increasingly layers AI agents on top of these processes to auto-triage requests, summarize cards, and trigger actions. Pipefy's key differentiator versus generic project-management tools like Trello or Monday.com is its purpose-built process and forms engine: every process is backed by structured intake forms, database-like relationships between records, role-based permissions, and reporting designed specifically for repeatable operational workflows rather than freeform task tracking, which makes it popular with operations, HR, finance, and IT teams that need governance and audit trails around their processes. Pipefy uses a freemium pricing model: a genuinely usable free Starter plan supports up to 10 users, 5 processes, and 50 cards created per month with basic automation; paid Business and Enterprise plans add unlimited processes, higher automation-job limits, role-based access control, single sign-on, white-labeling, and dedicated support, but pricing for these tiers is not published and requires contacting sales, with a discounted SMB plan available for companies with 11 to 200 employees. Pipefy's target customers range from small operations teams adopting their first structured workflow tool to large enterprises standardizing dozens of processes across HR, procurement, and IT service management. Named competitors in the no-code workflow and BPM space include monday.com, Trello, Process Street, and Kissflow, with Pipefy generally positioned as more process- and governance-oriented than lightweight task boards like Trello, while remaining more accessible to non-technical users than heavier enterprise BPM suites.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '67b19345-c927-42e2-946a-1bb82ab00b60';

