-- ── Pitivi ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pitivi is a free, open-source, non-linear video editor for Linux built on the GStreamer multimedia framework, offering a timeline-based interface for cutting, transitions, and effects.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$Volunteer-run open-source project (Pitivi Foundation)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source project, historically supported by Collabora)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Pitivi Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pitivi is a free, open-source video editor for Linux built on GStreamer. Explore its features, pricing, and alternatives like Kdenlive and Shotcut.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pitivi is a free and open-source, non-linear video editor for Linux, originally started in December 2003 by French developer Edward Hervey as an end-of-studies project at the EPITECH engineering school in Paris. The project's codebase was first checked into version control in 2004, initially written in C and rewritten in Python the following year; Hervey later joined Fluendo to work on the GStreamer multimedia framework and subsequently co-founded Collabora's Multimedia division in 2008, using that base to keep developing Pitivi, GStreamer, and the GNonLin and GStreamer Editing Services (GES) libraries that Pitivi relies on for importing, editing, and rendering video. Pitivi is licensed under the GNU Lesser General Public License (LGPL) and is closely associated with the GNOME desktop project, sharing its design language and toolkit; it has no traditional company behind it, instead being maintained by a volunteer open-source community and supported at times by the nonprofit Pitivi Foundation and by Collabora, with development funded through donations, GNOME infrastructure, and periodic Google Summer of Code participation rather than venture capital. Because Pitivi's editing and rendering pipeline is built entirely on GStreamer, it was the first open-source video editor to support the Material Exchange Format (MXF), and it benefits from GStreamer's very broad codec and container support. Key features include a multi-track timeline, clip trimming and transitions, an effects library, waveform-based audio alignment, media library tagging, and, in more recent releases, object tracking and beat detection to help align cuts to music. Pitivi briefly shipped as Ubuntu's default video editor starting with Ubuntu 10.04 in 2010, but was dropped from the default Ubuntu ISO in 2011 due to concerns about maturity and fit with mainstream users. As entirely free, open-source software, Pitivi has no pricing tiers or paid plans; its target users are Linux desktop users, GNOME users specifically, and open-source enthusiasts who want a native, no-cost timeline video editor without proprietary licensing or subscription fees. In the open-source video-editing space, Pitivi is most commonly compared to Kdenlive, a more feature-rich KDE-based competitor with broader adoption, Shotcut, and OpenShot, and, among proprietary tools, to the free tier of DaVinci Resolve, with Pitivi generally seen as simpler and more tightly scoped than Kdenlive but with a smaller feature set and contributor base.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '588dad8e-446f-42e3-8554-3bef2ef37a9a';

