INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Tiling image board$q$, $q$Displays saved images in a responsive, Pinterest-style masonry grid for easy visual browsing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Tagging and search$q$, $q$Every pin can be tagged, making it possible to filter and search a growing collection quickly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Boards and privacy controls$q$, $q$Content can be organized into public or private boards for personal use or shared team access.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Browser extensions and bookmarklet$q$, $q$One-click saving of images and webpages directly from the browser into a Pinry instance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$REST API and CLI$q$, $q$A Django REST Framework API and a command-line client enable scripting and automation of pins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Docker-based self-hosting$q$, $q$Official images for ARMv7, ARMv8, and AMD64 make deployment on servers, NAS boxes, or Raspberry Pi devices straightforward.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Multi-user support$q$, $q$Multiple accounts can share a single Pinry instance, each with their own boards and permissions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Internationalization$q$, $q$The interface is available in English, Simplified Chinese, and French.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Completely free and open source with no subscription or usage fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Full data ownership since everything is stored on infrastructure the user controls$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$No ads, tracking, or third-party data sharing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Simple, focused feature set that is easy to learn$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Docker support makes self-hosting relatively approachable for technical users$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Actively maintained community project with a permissive BSD license$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Requires self-hosting, Docker, or Django knowledge, which is a barrier for non-technical users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$No official hosted or managed version, so uptime and backups are the user's responsibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Smaller feature set than commercial moodboard or DAM tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Mobile experience and native apps are limited compared to mainstream services like Pinterest$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Development pace is slower than a funded commercial product, since it relies on volunteer contributors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$No built-in AI-powered tagging, search, or recommendations$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$What is Pinry used for$q$, $q$Pinry is used to save, tag, and visually organize images, videos, and webpages, similar to Pinterest, but on infrastructure the user controls rather than a third-party service.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Is Pinry free$q$, $q$Yes. Pinry is free, open-source software released under the BSD-2-Clause license. Users only pay for whatever hosting infrastructure they choose to run it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Do I need technical skills to run Pinry$q$, $q$Basic familiarity with Docker or Python and Django is helpful, since Pinry is self-hosted and does not offer an official managed cloud version.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$What technology is Pinry built with$q$, $q$Pinry uses a Python and Django REST Framework backend with a Vue.js frontend, and it is distributed with Docker images for multiple architectures.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Is Pinry a company or a product from a startup$q$, $q$No. Pinry is a community-maintained open-source project on GitHub with no company, funding, or commercial entity behind it.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Can Pinry be used by a team$q$, $q$Yes. Pinry supports multiple user accounts and public or private boards, so a small team can share a single self-hosted instance.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$What are the main alternatives to Pinry$q$, $q$Common alternatives include other self-hosted tools like Wallabag, Shaarli, and Linkding, as well as hosted services like Pinterest and Pocket.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Does Pinry have an API$q$, $q$Yes, Pinry exposes a full REST API through Django REST Framework, and it also ships a command-line client for scripted pinning.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Personal visual bookmarking$q$, $q$Individuals use Pinry as a private, ad-free alternative to Pinterest for saving design inspiration, recipes, or reference images.$q$, $q$Privacy-conscious individuals and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Team mood boards and reference libraries$q$, $q$Small design or creative teams self-host Pinry as a shared, tag-searchable repository of visual references and inspiration.$q$, $q$Small design and creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Home-lab and self-hosted stack addition$q$, $q$Self-hosting enthusiasts add Pinry to a home server or NAS alongside other open-source apps to keep personal media and bookmarks off third-party platforms.$q$, $q$Developers and home-lab hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under the BSD-2-Clause license","Unlimited boards, pins, and tags","Docker images for ARMv7, ARMv8, and AMD64","REST API and CLI access","Multi-user support with public and private boards","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pinry is an open-source, self-hosted image board that mimics the tiling, visual-discovery experience of Pinterest while keeping every image, tag, and board on infrastructure the user controls. It was created for people who want to curate a personal or team reference library of images, screenshots, and webpages without handing that data to a third-party platform.$q$, $q$Because Pinry is not a hosted SaaS product, there is no company behind it collecting fees or subscriptions. Instead, a community of contributors maintains the codebase on GitHub, ships Docker images for common architectures, and periodically cuts new releases, making it a durable option for people who prioritize data ownership and long-term availability over convenience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pinry organizes saved content into boards and lets users tag each pin for fast filtering and search later. A browser bookmarklet and extensions make it easy to save images and webpages while browsing, and a command-line tool and full REST API support scripted or automated pinning workflows.$q$, $q$The platform supports multiple user accounts with public and private boards, so it can serve as either a single-user archive or a small shared team resource. It is translated into English, Simplified Chinese, and French, and its Docker-based deployment supports ARMv7, ARMv8, and AMD64 hardware, including low-power devices like a Raspberry Pi.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pinry itself is completely free under the BSD-2-Clause open-source license; there are no paid tiers, subscriptions, or usage limits imposed by the software. Anyone can download, modify, and redistribute the source code.$q$, $q$The only real cost is hosting: users need a server, VPS, NAS, or home computer capable of running Docker (or a manual Python and Django installation) to self-host their instance, plus their own domain and storage if they want the board accessible outside their local network.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eed72c85-b8c1-41ad-bfa6-c1d425f02b1e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Embedded capital offers$q$, $q$Lets partner platforms present pre-approved financing offers to their own customers inside the platform's existing interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Revenue-based repayment$q$, $q$Financing repayment flexes with a business's sales performance rather than requiring fixed monthly loan payments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Risk underwriting from transaction data$q$, $q$Uses a partner platform's own transaction and revenue data to assess and price risk for financing offers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Vertical SaaS and marketplace focus$q$, $q$Purpose-built for software platforms serving specific verticals, payment facilitators, and marketplaces rather than consumers directly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$White-labeled integration$q$, $q$Financial tools appear under the partner platform's own brand rather than as a separate Pipe-branded product.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Media and entertainment financing$q$, $q$Following its acquisition of Purely Capital, Pipe extended embedded financing into media and entertainment revenue streams.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Non-dilutive financing that does not require giving up equity$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Revenue-based repayment can flex with a business's cash flow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Embedded model lets end customers access capital without leaving their existing software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Platform partners can add a new revenue stream and improve retention$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Backed by significant institutional funding and a multi-year operating history$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Established partnerships with recognizable platforms such as UberEats and GoCardless$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$No public, self-serve pricing, so terms require a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Primarily accessible through partner platforms rather than directly by most small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Publicly reported leadership departures in 2022 raised questions about internal stability$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Headquarters and company-size details vary across public sources, making some corporate facts hard to pin down$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Business model has changed significantly since 2019, which can make older public information about Pipe outdated$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Focused on recurring-revenue and transaction-based businesses, so it is not a fit for companies without steady revenue data$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$What does Pipe do today$q$, $q$Pipe provides embedded financial tools, primarily revenue-based capital, that software platforms can offer directly to their business customers under their own brand.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Is Pipe the same as trading future revenue on a marketplace$q$, $q$That was Pipe's original 2019 model. The company has since evolved into an embedded finance provider, with its Capital product now built for platform partners rather than a standalone trading marketplace.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Who uses Pipe$q$, $q$Pipe's direct customers are vertical SaaS companies, payment facilitators, and marketplace platforms; the small and mid-sized businesses on those platforms are the ultimate recipients of the financing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$How much does Pipe cost$q$, $q$Pipe does not publish pricing. Commercial and financing terms are custom and negotiated directly with Pipe's team.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Who founded Pipe$q$, $q$Pipe was founded in 2019 by Harry Hurst, Josh Mangel, and Zain Allarakhia.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Where is Pipe headquartered$q$, $q$Pipe is headquartered in Miami, Florida.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$What are alternatives to Pipe$q$, $q$Alternatives in the revenue-based and embedded financing space include Capchase, Clearco, Uncapped, and Stripe Capital.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Has Pipe raised funding$q$, $q$Yes. Pipe raised over $300 million and reached a reported valuation of about $2 billion in 2021, becoming a fintech unicorn.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Embedding financing into a vertical SaaS platform$q$, $q$A vertical software provider adds Pipe-powered financing offers so its business customers can access capital without leaving the platform.$q$, $q$Vertical SaaS and payment facilitator platforms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Marketplace working-capital offers$q$, $q$A marketplace platform uses Pipe to offer sellers upfront capital against future sales, improving seller retention and loyalty.$q$, $q$Marketplace and platform operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Non-dilutive growth capital for recurring-revenue businesses$q$, $q$A subscription or recurring-revenue business accesses financing tied to its revenue performance instead of raising equity or taking on fixed-payment debt.$q$, $q$SaaS and recurring-revenue business owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$Custom (Partner and Enterprise)$q$, $q$Custom (contact sales)$q$, $q$Negotiated$q$, NULL, $q$["Embedded capital offers tailored to the partner platform","Revenue-based repayment terms","Underwriting built on partner transaction data","White-labeled integration into the partner's product","Dedicated onboarding and account management"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pipe began in 2019 as a marketplace where SaaS companies could sell their future recurring revenue to institutional investors for immediate, non-dilutive cash, earning it comparisons to a 'trading platform for revenue.' The company grew quickly, becoming a unicorn within two years of launch.$q$, $q$The business has since shifted toward embedded finance: rather than positioning itself primarily as a direct-to-founder marketplace, Pipe now focuses on powering financing features inside other software platforms, letting vertical SaaS providers and marketplaces offer capital to their own end customers under their own brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pipe's core embedded product, Capital, uses a partner platform's existing transaction and revenue data to generate pre-approved financing offers for small businesses, with repayment structured around future sales rather than fixed monthly loan payments.$q$, $q$Because the financing is embedded, partner platforms can present capital offers directly inside the software their customers already use, without redirecting them to a bank or a separate lending application, which Pipe positions as improving retention and creating a new revenue stream for the partner.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61d2abfe-020b-44ad-8493-bab43284c852', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pipe does not publish self-serve pricing. Commercial terms, including fee structures for platform partners and financing terms for end businesses, are negotiated directly with Pipe's sales team on a custom basis.$q$, $q$Historically, when Pipe operated as a revenue-trading marketplace, it charged fees to both sides of a trade (reported at roughly 1% each); its current embedded-finance economics are shared between Pipe and its platform partners and are not publicly disclosed.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Code-level workflow steps$q$, $q$Insert custom Node.js, Python, Go, or Bash code directly into a workflow alongside no-code actions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Thousands of API integrations$q$, $q$Prebuilt triggers and actions connect to thousands of apps and APIs without custom authentication setup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Event-based triggers$q$, $q$Workflows can start from webhooks, schedules, email, HTTP requests, or app-specific events.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Pipedream Connect$q$, $q$Lets SaaS companies embed a white-labeled integration experience for their own end users inside their product.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Built-in AI steps$q$, $q$Workflows can include AI actions backed by a monthly pool of included AI tokens.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Credit-based compute billing$q$, $q$Usage is metered in credits tied to compute duration and memory rather than a flat per-workflow fee.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Package ecosystem access$q$, $q$Code steps can import npm and PyPI packages, giving workflows access to the broader open-source ecosystem.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Enterprise controls$q$, $q$The Business tier adds SSO, HIPAA support, VPC deployment, and SLAs for regulated or large organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Combines no-code speed with full custom code when needed$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Connects to thousands of APIs out of the box$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Generous free tier for testing and small personal workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Pipedream Connect provides a ready-made embedded integration solution for SaaS builders$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Credit-based pricing can be cost-efficient for lightweight, short-duration workflows$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Now backed by Workday's resources following the November 2025 acquisition$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Credit-based billing can be harder to predict than flat per-task pricing for long-running workflows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Requires at least some coding comfort to get full value versus pure no-code tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Free tier is capped at only three active workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Business tier pricing is not public and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Post-acquisition roadmap and independence from Workday's enterprise priorities is still unfolding$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Higher-usage workflows can become expensive compared to flat-rate automation tools$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$What is Pipedream used for$q$, $q$Pipedream is used to build workflow automations and API integrations that combine no-code steps with custom code, connecting apps and services without managing your own infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Is Pipedream free$q$, $q$Yes, Pipedream has a free plan with a limited daily credit allowance, three active workflows, and one million AI tokens per month. Paid plans start at $29 per month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Do I need to know how to code to use Pipedream$q$, $q$No, but coding ability unlocks Pipedream's biggest advantage, the ability to write custom Node.js, Python, Go, or Bash code inside a workflow step.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$What are Pipedream credits$q$, $q$Credits meter compute usage; one credit generally corresponds to about 30 seconds of workflow execution at 256MB of memory, and each paid plan includes a monthly credit allowance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$What is Pipedream Connect$q$, $q$Connect is Pipedream's embedded-integration product that lets SaaS companies offer a white-labeled way for their own end users to connect third-party accounts inside the SaaS company's product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Who owns Pipedream now$q$, $q$Pipedream was acquired by Workday in November 2025 to extend AI agent integrations across Workday's applications, though its self-serve product and pricing have remained live and unchanged.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$How is Pipedream different from Zapier$q$, $q$Pipedream exposes full custom code alongside no-code actions, while Zapier is primarily a no-code, point-and-click automation tool with more limited code capabilities.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$What are alternatives to Pipedream$q$, $q$Common alternatives include Zapier, Make, n8n, and Workato, each with different balances of no-code simplicity versus developer flexibility.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Custom API workflow automation$q$, $q$A developer builds a workflow that receives a webhook, transforms the payload with custom code, and pushes data into a database or third-party API.$q$, $q$Software developers and technical founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Embedded integrations for a SaaS product$q$, $q$A SaaS company uses Pipedream Connect to let its own customers connect third-party accounts inside the product, without building OAuth flows in-house.$q$, $q$SaaS product and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Internal tooling and ops automation$q$, $q$An operations or engineering team automates internal processes, like syncing data between internal tools, using a mix of prebuilt actions and custom scripts.$q$, $q$Internal engineering and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Limited daily credit allowance","Up to 3 active workflows","1 million AI tokens per month","Unlimited connected accounts for development"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Basic$q$, $q$$29/month$q$, $q$Annual (higher on month-to-month billing)$q$, NULL, $q$["Monthly credit allocation for compute usage","20 million AI tokens per month","More active workflows than Free tier","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Advanced$q$, $q$$49/month$q$, $q$Annual (higher on month-to-month billing)$q$, NULL, $q$["Increased monthly credit allocation","50 million AI tokens per month","Higher workflow and account limits","Standard support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Connect$q$, $q$$99/month$q$, $q$Annual (higher on month-to-month billing)$q$, NULL, $q$["10,000 monthly credits for compute usage","50 million AI tokens per month","Authentication for external end users via Pipedream Connect","Additional external users billed per user"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$Business$q$, $q$Custom$q$, $q$Negotiated$q$, NULL, $q$["Custom volume-based credit pricing","Single sign-on (SSO)","HIPAA support and VPC deployment","Service-level agreements (SLAs)"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pipedream is a workflow automation and API integration platform aimed squarely at developers. Rather than forcing every step into a rigid no-code action, it lets users write actual Node.js, Python, Go, or Bash code inline within a workflow, alongside prebuilt connectors for thousands of third-party APIs.$q$, $q$Founded in San Francisco in 2019, Pipedream grew from developer tooling roots (including the earlier RequestBin project) into a broader automation and embedded-integration platform, and was acquired by Workday in November 2025 to extend AI agent integrations across Workday's enterprise applications, while its self-serve product continues to operate independently.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Workflows in Pipedream are triggered by events such as HTTP webhooks, schedules, email, or app-specific triggers, and can mix prebuilt actions with custom code steps that pull in npm or PyPI packages. This lets a single workflow, for example, receive a webhook, transform data with a few lines of JavaScript, and then call a Slack or database API.$q$, $q$Pipedream Connect extends this into an embedded-integration product, letting SaaS companies offer their own end users a white-labeled way to connect third-party accounts inside the SaaS company's own product, without building and maintaining OAuth and API integrations themselves.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pipedream's Free plan includes a limited daily credit allowance, up to three active workflows, and one million AI tokens per month, with no credit card required to start.$q$, $q$Paid annual-billing plans are Basic at $29 per month, Advanced at $49 per month, and Connect at $99 per month (higher on month-to-month billing), each bundling a monthly credit allocation for compute usage; a custom-priced Business tier adds SSO, HIPAA support, VPC deployment, and SLAs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9e7e7d01-4172-4d85-90b4-cb0af1a7c91d', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Visual sales pipeline$q$, $q$A drag-and-drop, Kanban-style pipeline view lets reps track deals through custom stages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Activity-based selling$q$, $q$Automated reminders and activity tracking keep reps focused on the next action for each deal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Email sync and tracking$q$, $q$Two-way email integration with open and click tracking directly inside deal records.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Workflow automation$q$, $q$Rule-based automation handles repetitive tasks like follow-up emails and deal-stage updates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Sales forecasting and reporting$q$, $q$Custom dashboards and revenue forecasting give visibility into pipeline health and team performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$AI Sales Assistant$q$, $q$Surfaces deal insights, performance trends, and recommended next actions using AI.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Marketplace and API$q$, $q$Integrates with hundreds of third-party apps such as Slack, Zoom, and QuickBooks, plus a public API for custom integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Add-on modules$q$, $q$Optional LeadBooster, web forms, Campaigns email marketing, and Projects modules extend the core CRM.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Intuitive, visual pipeline that is easy for sales reps to adopt quickly$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Strong activity and follow-up automation to keep deals moving$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Wide range of native integrations and a public API$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Scales from small teams up to larger organizations across five pricing tiers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$AI Sales Assistant adds proactive insights without extra setup$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Backed by a well-established company with over a decade of CRM focus$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$No permanent free plan, only a free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Costs can rise quickly once add-ons like LeadBooster or Campaigns are included$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Higher-tier features such as advanced permissions and forecasting are locked behind pricier plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Less suited to complex, multi-department revenue operations than heavier platforms like Salesforce$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Reporting customization is more limited than some higher-end competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Per-user pricing can become expensive for larger sales teams$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$What is Pipedrive$q$, $q$Pipedrive is a sales-focused CRM built around a visual, drag-and-drop pipeline that helps sales teams track deals, automate follow-ups, and forecast revenue.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$How much does Pipedrive cost$q$, $q$Pipedrive's paid plans range from around $12.50 per user per month for Essential up to around $74.90 per user per month for Enterprise, billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Does Pipedrive have a free plan$q$, $q$No, Pipedrive does not offer a permanent free plan, but it provides a free trial so teams can test the product before subscribing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Who founded Pipedrive$q$, $q$Pipedrive was founded in 2010 in Tallinn, Estonia, by Timo Rein, Urmas Purde, Ragnar Sass, Martin Henk, and Martin Tajur.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Who owns Pipedrive now$q$, $q$Vista Equity Partners acquired a majority stake in Pipedrive in 2020, in a deal that valued the company at approximately $1.5 billion.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$What is Pipedrive best for$q$, $q$Pipedrive is best suited to small and mid-sized sales teams that want a simple, visual way to manage a sales pipeline without the complexity of larger enterprise CRM suites.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$What are the main alternatives to Pipedrive$q$, $q$Common alternatives include HubSpot CRM, Salesforce Sales Cloud, Zoho CRM, and Close.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Does Pipedrive integrate with other tools$q$, $q$Yes, Pipedrive has a marketplace with hundreds of integrations, including Slack, Zoom, QuickBooks, and Mailchimp, along with a public API.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Small business sales pipeline management$q$, $q$A small business sales team adopts Pipedrive to replace spreadsheets with a visual pipeline and automated follow-up reminders.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Scaling a mid-sized sales organization$q$, $q$A growing sales department uses Pipedrive's Professional or Power plans to add forecasting, custom reporting, and permission controls as headcount increases.$q$, $q$Mid-sized B2B sales organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Lead generation to deal-close workflow$q$, $q$A team combines Pipedrive's core CRM with the LeadBooster add-on to capture leads via chatbot and web forms and move them directly into the sales pipeline.$q$, $q$Sales and marketing teams generating inbound leads$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Essential$q$, $q$$12.50/user/month$q$, $q$Annual (higher month-to-month)$q$, NULL, $q$["Visual sales pipeline","Activity and goal tracking","Email sync","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Advanced$q$, $q$$24.90/user/month$q$, $q$Annual (higher month-to-month)$q$, NULL, $q$["Everything in Essential","Full email sync and templates","Workflow automation","Meeting scheduling tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Professional$q$, $q$$49.90/user/month$q$, $q$Annual (higher month-to-month)$q$, NULL, $q$["Everything in Advanced","Revenue forecasting","Custom reports and dashboards","Enhanced automation limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Power$q$, $q$$59.90/user/month$q$, $q$Annual (higher month-to-month)$q$, NULL, $q$["Everything in Professional","Advanced permissions and visibility controls","Project management features","Phone support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Enterprise$q$, $q$$74.90/user/month$q$, $q$Annual (higher month-to-month)$q$, NULL, $q$["Everything in Power","Enhanced security controls","Unlimited reports and permission sets","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pipedrive was built by former salespeople who were frustrated with existing CRMs being designed around contact databases rather than the actual sales process. That origin shaped its core product: a visual pipeline where deals move through stages, making pipeline health and next actions immediately visible.$q$, $q$Since a 2020 majority investment from Vista Equity Partners, Pipedrive has expanded well beyond its original pipeline view, adding AI-assisted sales tools, marketing and lead-generation add-ons, and a broader automation layer, while continuing to market itself primarily to small and mid-sized sales teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Pipedrive offers customizable, drag-and-drop sales pipelines, activity reminders, email sync and tracking, and sales forecasting, all designed to keep reps focused on the next action needed to move a deal forward.$q$, $q$Higher tiers add workflow automation, custom reporting and dashboards, revenue forecasting, granular permission and visibility controls, and an AI Sales Assistant, while optional add-ons cover lead generation (LeadBooster), web forms, email marketing campaigns, and post-sale project management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pipedrive is sold as a per-user monthly subscription across five tiers: Essential, Advanced, Professional, Power, and Enterprise, with annual billing offering significant savings over month-to-month pricing.$q$, $q$There is no free-forever plan, but Pipedrive offers a free trial so teams can evaluate the product before committing. Several add-on modules, including LeadBooster and Campaigns, are priced and billed separately from the core subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$No-code process builder$q$, $q$Business users design structured workflows with Kanban-style boards, no developer involvement required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Structured intake forms$q$, $q$Each process starts from a customizable form that captures consistent, structured data for every request.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Conditional automation rules$q$, $q$If-this-then-that logic automates approvals, notifications, and task routing within a process.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$AI agents$q$, $q$AI can triage incoming requests, summarize cards, and trigger actions within a workflow automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Role-based permissions$q$, $q$Granular access controls determine who can view, edit, or approve items within a process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$SLA management$q$, $q$Service-level agreement tracking flags overdue or at-risk items within a process.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Reporting and dashboards$q$, $q$Built-in dashboards surface process bottlenecks, cycle times, and team performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$API and integrations$q$, $q$Connects to other business systems via API and prebuilt integrations for data exchange across tools.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Usable free Starter plan for small teams with up to 10 users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$No-code process builder is accessible to non-technical business users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Purpose-built for structured, repeatable processes rather than freeform tasks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$AI agents can automate request triage and routine actions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Strong governance features like SLAs, permissions, and audit trails$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Discounted SMB plan available for smaller companies$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Business and Enterprise pricing is not public and requires a sales call$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Starter plan's limits (5 processes, 50 cards per month) are restrictive for growing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Per-user billing on paid plans can get expensive at scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Some users report the platform's US dollar pricing is costly for teams outside the US, including in Brazil$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Steeper learning curve than simple Kanban tools like Trello for first-time process design$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Advanced customization may require internal process-ops expertise to get full value$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$What is Pipefy used for$q$, $q$Pipefy is used to design, run, and automate structured business processes such as onboarding, procurement, IT service requests, and accounts payable using no-code Kanban-style boards.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Is Pipefy free$q$, $q$Pipefy offers a free Starter plan for up to 10 users, 5 processes, and 50 cards per month. Business and Enterprise plans require contacting sales for pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Who founded Pipefy$q$, $q$Pipefy was founded in 2015 in Curitiba, Brazil, by Alessio Alionco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Is Pipefy no-code$q$, $q$Yes, Pipefy is designed so business users can build and modify structured workflows without writing code.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$How is Pipefy different from Trello or Monday.com$q$, $q$Pipefy is built specifically for structured, repeatable business processes with forms, conditional logic, and governance features, whereas Trello and Monday.com are more general-purpose task and project boards.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Does Pipefy use AI$q$, $q$Yes, Pipefy includes AI agents that can triage requests, summarize cards, and trigger actions within a workflow.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Where is Pipefy headquartered$q$, $q$Pipefy is headquartered in San Francisco, California, with a significant ongoing presence in Brazil, where it was originally founded.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$What are alternatives to Pipefy$q$, $q$Common alternatives include monday.com, Trello, Process Street, and Kissflow.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$HR onboarding and offboarding$q$, $q$An HR team standardizes new-hire onboarding and employee offboarding into a structured, auditable process with automated task routing.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Procurement and purchase request management$q$, $q$A finance or operations team routes purchase requests through approval stages with SLAs and role-based permissions.$q$, $q$Procurement and finance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$IT service desk and support requests$q$, $q$An IT team uses Pipefy to intake, triage, and resolve internal support tickets with automation and reporting on response times.$q$, $q$IT service management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 10 users","Up to 5 processes","50 cards created per month","Basic automations and 15 automation jobs per month","2GB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Business$q$, $q$Custom (contact sales)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited processes","Per-user billing for unlimited users","300 automation jobs per month","API access and role-based access control","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited processes and custom storage limits","2,000 automation jobs per month","Single sign-on and two-factor authentication","White-labeling and dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pipefy was founded in Curitiba, Brazil in 2015 to give business teams a way to standardize and automate repeatable processes without needing developers or a heavyweight BPM implementation. It has since grown into a global company with a San Francisco headquarters and a continued strong Brazilian presence.$q$, $q$The platform is used to run structured, recurring workflows, such as onboarding, procurement, and service requests, rather than freeform project tracking, and it increasingly incorporates AI agents to triage and act on incoming requests automatically.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pipefy processes, called pipes, are built on Kanban-style boards backed by structured intake forms, conditional logic, and database-like relationships between records, giving each process governance and reporting that generic task boards lack.$q$, $q$Automation rules, SLAs, role-based permissions, and AI agents let teams reduce manual handoffs, while dashboards and reporting give managers visibility into process bottlenecks and performance across HR, finance, procurement, and IT service workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pipefy offers a free Starter plan that supports up to 10 users, 5 processes, and 50 cards created per month, making it usable for small teams without a credit card.$q$, $q$Business and Enterprise plans unlock unlimited processes, higher automation limits, SSO, white-labeling, and dedicated support, but pricing for both is custom and requires contacting sales; a discounted SMB plan is available for companies with 11 to 200 employees.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('67b19345-c927-42e2-946a-1bb82ab00b60', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Customizable sales pipelines$q$, $q$Teams can configure multiple pipelines and stages to match their specific sales process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Deal and activity tracking$q$, $q$Tracks deals, tasks, and communications tied to each contact and opportunity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Email tracking and templates$q$, $q$Tracks email opens and engagement, with templates and drip campaigns available on higher tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Performance Pulse analytics$q$, $q$Surfaces rep and team performance metrics and trends over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Map View territory routing$q$, $q$Visualizes contacts and accounts geographically to help plan sales routes and territories.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Project management with Kanban and Gantt views$q$, $q$Tracks post-sale implementation or account-management work alongside the sales pipeline.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Advanced de-duplication$q$, $q$Identifies and merges duplicate contact and company records to keep data clean.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Flat, published per-user pricing$q$, $q$Publishes clear per-user pricing with no seat minimums or mandatory onboarding fees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Transparent, publicly published per-user pricing with no seat minimums$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$No mandatory onboarding fees, making it easy to get started quickly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Simple, sales-native focus without unnecessary marketing or service bloat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Performance Pulse and Map View add useful analytics and routing beyond basic pipeline tracking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Grow tier includes project management, reducing the need for a separate tool$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Long operating history dating back to 2006 as PipelineDeals$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Fewer marketing and customer-service features than all-in-one CRM suites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Lower tiers cap the number of pipelines and active deals$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Company size and broader corporate details are not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Smaller ecosystem of third-party integrations compared to larger CRMs like Salesforce or HubSpot$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Data enrichment and email validation are separate paid add-ons rather than included features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Less brand recognition than category leaders like Salesforce, HubSpot, or Pipedrive$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$What is Pipeline CRM$q$, $q$Pipeline CRM, formerly known as PipelineDeals, is a sales pipeline and deal management CRM built for small and mid-sized B2B sales teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$How much does Pipeline CRM cost$q$, $q$Pipeline CRM's standard tiers are Start at $25/user/month, Develop at $33/user/month, and Grow at $49/user/month, billed annually, with a custom Enterprise tier available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Was Pipeline CRM previously called something else$q$, $q$Yes, Pipeline CRM was originally launched in 2006 as PipelineDeals and was rebranded and rebuilt as Pipeline CRM in the early 2020s.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Who founded Pipeline CRM$q$, $q$PipelineDeals, the predecessor to Pipeline CRM, was founded in 2006 by JP Werlin and Nick Bertolino in Seattle.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Does Pipeline CRM include project management$q$, $q$Yes, the Grow tier includes project management with Kanban and Gantt views for tracking post-sale or implementation work.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Is there a free trial for Pipeline CRM$q$, $q$Yes, Pipeline CRM offers a free trial, commonly highlighted on its Grow plan, with no credit card required.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$What are alternatives to Pipeline CRM$q$, $q$Common alternatives include Pipedrive, HubSpot CRM, Close, and Salesforce.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Where is Pipeline CRM based$q$, $q$Pipeline CRM is headquartered in Seattle, Washington, and serves users in roughly 60 countries.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Replacing spreadsheets for a small sales team$q$, $q$A small B2B sales team moves from spreadsheets to Pipeline CRM's Start plan to get a shared, visual pipeline with basic tracking.$q$, $q$Small B2B sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Territory-based field sales$q$, $q$A field sales team uses Map View to plan routes and visualize accounts geographically alongside standard pipeline tracking.$q$, $q$Field and territory-based sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Post-sale account management and onboarding$q$, $q$A sales and customer-success team uses the Grow plan's project management features to track implementation work after a deal closes.$q$, $q$Mid-sized B2B sales and customer-success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Start$q$, $q$$25/user/month$q$, $q$Annual (billed monthly at $29/user/month)$q$, NULL, $q$["1 sales pipeline","250 active deals per account","25 custom fields","1 automation","250 email tracking per user"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Develop$q$, $q$$33/user/month$q$, $q$Annual (billed monthly at $39/user/month)$q$, NULL, $q$["2 sales pipelines","2,500 active deals per account","Unlimited exports and email tracking","10 automations","Performance Pulse and Milestones features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Grow$q$, $q$$49/user/month$q$, $q$Annual (billed monthly at $59/user/month)$q$, NULL, $q$["5 sales pipelines and unlimited active deals","20 automations","Email templates, bulk emails, and drip campaigns","Advanced de-duplication","Project management with Kanban and Gantt views"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$Enterprise$q$, $q$Custom$q$, $q$Negotiated$q$, NULL, $q$["20 sales pipelines","Unlimited deals and team members","Flexible contract terms","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pipeline CRM began life in 2006 as PipelineDeals, one of the earlier standalone sales-pipeline tools built specifically for B2B sales teams rather than as a broader business suite. It was rebranded and rebuilt as Pipeline CRM in the early 2020s with a modernized interface and expanded feature set.$q$, $q$Headquartered in Seattle, the company positions itself around simplicity and pricing transparency, serving more than 18,000 users across roughly 60 countries, largely small and mid-sized B2B sales organizations looking for a fast-to-implement, sales-native CRM.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include customizable sales pipelines, deal and activity tracking, email tracking, and Performance Pulse analytics that surface rep and team performance trends over time.$q$, $q$Higher tiers add Map View territory routing, email templates and drip campaigns, advanced contact de-duplication, and integrated project management with Kanban and Gantt views for tracking post-sale or implementation work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2ab1000-e26f-4d01-88d3-85475427db72', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pipeline CRM publishes flat, per-user pricing across three standard tiers, Start, Develop, and Grow, billed monthly or annually, with annual billing offering meaningful savings, plus a custom Enterprise tier for larger deployments.$q$, $q$The company advertises no seat minimums and no mandatory onboarding fees. Optional add-ons, including data enrichment and email validation credits, are billed separately from the core subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Cookieless visitor tracking$q$, $q$Identifies unique visitors using server-side hashing instead of cookies, typically removing the need for a consent banner.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Real-time dashboards$q$, $q$Shows live traffic, referrers, and page performance as visitors arrive on the site.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Custom events and conversion goals$q$, $q$Tracks specific user actions and conversion events beyond basic pageviews.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Funnel and session analysis$q$, $q$Visualizes how visitors move through a site and where they drop off.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Built-in URL shortener$q$, $q$Generates and tracks shortened links directly within the Pirsch dashboard.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$A/B testing and segmentation$q$, $q$Available on higher tiers to compare page variants and segment audience behavior.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Google Analytics import$q$, $q$Lets teams migrate historical data from Google Analytics into Pirsch.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$API and SDKs$q$, $q$Enables developers to send tracking data from custom apps, not just standard web pages.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$No cookie-consent banner typically required due to cookieless tracking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$GDPR-friendly with EU-based hosting and 100% data ownership$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Usage-based pricing tied to page views rather than per-seat fees$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Open-source tracking core adds transparency and auditability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Unlimited team members even on the entry-level Standard plan$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Bootstrapped company with a straightforward, ad-free business model$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$No permanent free tier, only a 30-day free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Smaller feature set than full-scale analytics platforms like Google Analytics 4$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Small, bootstrapped team may mean slower feature velocity than VC-backed competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Advanced features like A/B testing and white-labeling require the Plus tier or higher$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Enterprise features such as on-premise installation and SSO require custom sales pricing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Less brand recognition than larger privacy-analytics competitors like Plausible$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$What is Pirsch used for$q$, $q$Pirsch is used as a privacy-friendly, cookieless website analytics tool that gives GDPR-compliant traffic and conversion insights, typically without requiring a cookie-consent banner.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Is Pirsch really cookieless$q$, $q$Yes, Pirsch identifies unique visitors using server-side hashing techniques rather than storing cookies in the browser.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$How much does Pirsch cost$q$, $q$Pirsch starts at $6/month for the Standard plan, covering up to 10,000 monthly page views, with the Plus plan starting at $12/month and Enterprise available on request.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Does Pirsch have a free trial$q$, $q$Yes, Pirsch offers a 30-day free trial with no credit card required, though it does not have a permanent free plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Who founded Pirsch$q$, $q$Pirsch was founded in 2019 by Marvin Blum and Daniel Schramm, based in Rheda-Wiedenbrück, Germany, under the company Emvi Software GmbH.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Is Pirsch GDPR compliant$q$, $q$Yes, Pirsch is built around GDPR compliance, with EU-based hosting, no cross-site tracking, and full data ownership for customers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Can Pirsch import data from Google Analytics$q$, $q$Yes, Pirsch supports importing historical data from Google Analytics for teams migrating away from it.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$What are alternatives to Pirsch$q$, $q$Common alternatives include Plausible Analytics, Fathom Analytics, and Simple Analytics.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$GDPR-compliant analytics without a cookie banner$q$, $q$A European business replaces Google Analytics with Pirsch to get traffic insights while avoiding a cookie-consent banner.$q$, $q$EU-based businesses and privacy-focused site owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Agency analytics across multiple client sites$q$, $q$A digital agency uses Pirsch's Plus plan to manage analytics, white-labeled reporting, and unlimited websites for its clients.$q$, $q$Marketing and web design agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Conversion tracking for indie and small SaaS sites$q$, $q$An indie developer tracks signups and conversion goals for a small SaaS product without the complexity of Google Analytics 4.$q$, $q$Indie developers and small SaaS teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Standard$q$, $q$$6/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 10,000 monthly page views","Up to 50 websites","Unlimited team members and data retention","Events and conversion goal tracking","Built-in URL shortener","RESTful API and SDKs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Plus$q$, $q$$12/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Standard","Unlimited websites","Funnels and advanced URL shortener","A/B testing and segmentation","Custom domains and extensive white-labeling","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Negotiated$q$, NULL, $q$["Everything in Plus","Managed cloud or on-premise installation","SAML-based single sign-on","Raw data access","Personal onboarding and dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pirsch is a website analytics tool built specifically around privacy and regulatory compliance. It was founded in 2019 in Rheda-Wiedenbrück, Germany, by Marvin Blum and Daniel Schramm as a bootstrapped alternative to Google Analytics for site owners who want traffic insights without cookie banners or third-party data sharing.$q$, $q$Because Pirsch does not use cookies to identify visitors, sites relying on it can typically avoid displaying a cookie-consent banner under GDPR, which is a major draw for European businesses and privacy-conscious teams elsewhere.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pirsch provides real-time dashboards, custom event and conversion goal tracking, session and funnel analysis, and a built-in URL shortener, along with an API and SDKs for integrating tracking into custom applications beyond standard websites.$q$, $q$Higher tiers add unlimited websites, funnel visualization, A/B testing and segmentation, custom domains, and extensive white-labeling, making Pirsch suitable for agencies managing analytics across many client sites.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c25d8ee5-3608-4fe0-8763-83ed5faa70fe', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pirsch prices by monthly page views rather than by seat, starting at $6/month for the Standard plan covering up to 10,000 monthly page views and up to 50 websites.$q$, $q$The Plus plan starts at $12/month and unlocks unlimited websites and advanced features, while Enterprise pricing is custom and adds on-premise installation and SAML SSO. A 30-day free trial is available with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Multi-track timeline editing$q$, $q$Arrange, trim, and layer video and audio clips across multiple tracks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$GStreamer-powered import and export$q$, $q$Leverages the GStreamer framework for broad codec and container support, including MXF.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Transitions and effects library$q$, $q$Apply built-in transitions and video effects directly within the timeline.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Waveform-based audio alignment$q$, $q$Automatically aligns clips using audio waveforms for more precise syncing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Media library with tagging$q$, $q$Organizes imported clips with tags for easier retrieval in longer projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Object tracking and beat detection$q$, $q$Recent releases add object tracking and music beat detection to assist with precise cuts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Native GNOME integration$q$, $q$Shares GTK-based design and workflow conventions with the GNOME desktop environment.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Completely free with no subscriptions, watermarks, or paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Open-source and auditable under the LGPL license$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Deep GStreamer integration gives broad codec and container support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Clean, GNOME-native interface that is straightforward to learn$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$No vendor lock-in since projects and the software itself remain fully open$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Long project history dating back to 2003 with continued community development$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Linux-focused, with no official native macOS or Windows builds$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Smaller feature set and contributor base than Kdenlive, its closest open-source rival$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Development pace depends on volunteer and sponsor availability rather than a dedicated commercial team$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Historically has had stability and polish issues, which led Ubuntu to drop it as the default editor in 2011$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Less suited to complex, professional post-production work than paid tools like DaVinci Resolve Studio or Adobe Premiere Pro$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Documentation and tutorials are less extensive than for more mainstream editors$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$What is Pitivi$q$, $q$Pitivi is a free, open-source, non-linear video editor for Linux built on the GStreamer multimedia framework and closely tied to the GNOME desktop project.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Is Pitivi free$q$, $q$Yes, Pitivi is completely free and open source under the GNU Lesser General Public License, with no paid tiers or subscriptions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Who created Pitivi$q$, $q$Pitivi was started in December 2003 by French developer Edward Hervey as an end-of-studies project at the EPITECH engineering school in Paris.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Does Pitivi run on Windows or macOS$q$, $q$Pitivi is built primarily for Linux; it does not have official native Windows or macOS builds in the way mainstream commercial editors do.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$What is Pitivi built on$q$, $q$Pitivi is built on the GStreamer multimedia framework and its GStreamer Editing Services (GES) libraries, which handle media import, editing, and rendering.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Was Pitivi ever the default video editor on Ubuntu$q$, $q$Yes, Pitivi was the default video editor bundled with Ubuntu starting with Ubuntu 10.04 in 2010, but it was removed from the default Ubuntu ISO starting with Ubuntu 11.10 in 2011.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$How is Pitivi funded$q$, $q$Pitivi is funded through community donations, historical corporate sponsorship from Collabora, and periodic participation in programs like Google Summer of Code, rather than commercial sales.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$What are alternatives to Pitivi$q$, $q$Common open-source alternatives include Kdenlive, Shotcut, and OpenShot, while DaVinci Resolve's free tier is a common proprietary comparison.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Free video editing on Linux desktops$q$, $q$A Linux desktop user edits home videos or short projects using Pitivi as a native, no-cost alternative to proprietary editors.$q$, $q$Linux and GNOME desktop users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Learning non-linear video editing concepts$q$, $q$A student or hobbyist uses Pitivi's straightforward timeline interface to learn cutting, transitions, and effects without a subscription cost.$q$, $q$Students and hobbyist video editors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Open-source multimedia projects and contributions$q$, $q$A developer contributes to Pitivi's codebase or uses it as a reference implementation of GStreamer Editing Services for their own multimedia project.$q$, $q$Open-source developers and GStreamer contributors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under the LGPL license","Multi-track timeline editing","GStreamer-powered import and export with broad codec support","Effects, transitions, and audio alignment tools","No watermarks, subscriptions, or paid tiers","Community and donation-based support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pitivi began in December 2003 as a student project by Edward Hervey at the EPITECH engineering school in Paris, and grew into a full non-linear video editor for Linux tightly integrated with the GNOME desktop and the GStreamer multimedia framework.$q$, $q$Pitivi has no owning company; it is developed by a volunteer open-source community, historically supported by Collabora's Multimedia division and the nonprofit Pitivi Foundation, and funded through donations and community infrastructure rather than commercial sales.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pitivi offers a multi-track timeline for cutting, trimming, and arranging clips, along with transitions, an effects library, and waveform-based audio alignment, all built on GStreamer's editing services for import, playback, and rendering.$q$, $q$Because it inherits GStreamer's codec and container support, Pitivi was the first open-source video editor to support the Material Exchange Format (MXF), and recent releases have added object tracking and beat detection to help editors align cuts to music.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pitivi is completely free, licensed under the GNU Lesser General Public License (LGPL), with no paid tiers, subscriptions, or watermarks of any kind.$q$, $q$The project accepts voluntary donations to fund ongoing development, and has historically benefited from corporate sponsorship (notably from Collabora) and periodic participation in programs like Google Summer of Code.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('588dad8e-446f-42e3-8554-3bef2ef37a9a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
